$ErrorActionPreference = 'Stop'

function Fail([string]$Message) {
  Write-Error "[FAIL] $Message"
  exit 1
}

function Check-Contains([string]$File, [string]$Pattern, [string]$Message) {
  $content = Get-Content -Raw -LiteralPath $File
  if (-not [regex]::IsMatch($content, $Pattern)) {
    Fail $Message
  }
}

function Check-NotContains([string]$File, [string]$Pattern, [string]$Message) {
  $content = Get-Content -Raw -LiteralPath $File
  if ([regex]::IsMatch($content, $Pattern)) {
    Fail $Message
  }
}

function Check-NotExactLine([string]$File, [string]$Exact, [string]$Message) {
  $lines = Get-Content -LiteralPath $File
  if ($lines -contains $Exact) {
    Fail $Message
  }
}

foreach ($script in @('freedom.sh', 'vps_init_tool.sh', 'xray-1stream-dat.sh')) {
  if (-not (Test-Path -LiteralPath $script)) {
    Fail "missing script: $script"
  }
}

$vpsCount = @(Get-ChildItem -File -Filter 'vps_init_tool*.sh').Count
if ($vpsCount -ne 1) {
  Fail "expected exactly one vps_init_tool*.sh, found $vpsCount"
}

