Check-Contains 'freedom.sh' 'spx=\$\{encoded_spider_x\}' 'freedom.sh share link must use generated spiderX'
Check-Contains 'freedom.sh' 'network: "raw"' 'freedom.sh REALITY transport should use official raw network'
Check-Contains 'freedom.sh' 'type=raw' 'freedom.sh share link must use raw network'
Check-NotContains 'freedom.sh' 'network: "tcp"' 'freedom.sh should not use legacy tcp network spelling for REALITY'
Check-NotContains 'freedom.sh' 'type=tcp' 'freedom.sh share link should not use legacy tcp type'
Check-NotContains 'freedom.sh' 'spx=%2F' 'freedom.sh should not pin spiderX to root path'
Check-Contains 'freedom.sh' '--check, --preflight' 'freedom.sh missing read-only preflight CLI option'
Check-Contains 'freedom.sh' 'clear_screen\(\)' 'freedom.sh missing non-interactive clear guard'
Check-Contains 'freedom.sh' 'verify_service_port_listening\(\)' 'freedom.sh missing post-restart port listener verification'
Check-Contains 'freedom.sh' 'verify_service_port_listening' 'freedom.sh restart flow must verify the service port is listening'
Check-Contains 'freedom.sh' 'not listening on TCP port' 'freedom.sh must report missing post-restart listener'
Check-Contains 'freedom.sh' 'Xray config install failed' 'freedom.sh must handle config install failures explicitly'
Check-Contains 'freedom.sh' 'if ! install -m 600 "\$tmp" "\$CONFIG_PATH"; then' 'freedom.sh config install must not rely on errexit'
Check-Contains 'freedom.sh' 'fallback: xray -test -config' 'freedom.sh config validation must preserve fallback test diagnostics'
Check-Contains 'freedom.sh' 'usage_error\(\)' 'freedom.sh missing CLI usage error helper'
Check-Contains 'freedom.sh' 'require_option_value\(\)' 'freedom.sh missing CLI option value validator'
Check-Contains 'freedom.sh' 'require_option_value "--sni"' 'freedom.sh CLI must validate --sni values'
Check-Contains 'freedom.sh' 'require_option_value "--xray-encryption"' 'freedom.sh CLI must validate --xray-encryption values'
Check-Contains 'freedom.sh' 'validate_generated_config "\$tmp"' 'freedom.sh must validate generated temp config before installing it'
Check-Contains 'freedom.sh' '"\$BIN" run -test -c "\$config_file"' 'freedom.sh temp config validation must use xray run -test before install'
Check-Contains 'freedom.sh' 'H2 is recommended, not mandatory' 'freedom.sh must treat missing H2 as a warning instead of a hard failure'
Check-NotContains 'freedom.sh' '\[\[ "\$tls_ok" -ne 1 \|\| "\$h2_ok" -ne 1 \]\]' 'freedom.sh must not require H2 for SNI usability'
Check-Contains 'freedom.sh' '\{"type":"field","ip":\["geoip:private"\],"outboundTag":"block"\}' 'freedom.sh route must block private IP first'
Check-Contains 'freedom.sh' '\{"type":"field","protocol":\["bittorrent"\],"outboundTag":"block"\}' 'freedom.sh route must block bittorrent traffic through Xray'
Check-Contains 'freedom.sh' '\{"type":"field","domain":\["geosite:geolocation-!cn"\],"outboundTag":"direct"\}' 'freedom.sh route must direct known non-CN domains before CN blocks'
Check-Contains 'freedom.sh' '\{"type":"field","domain":\["geosite:cn"\],"outboundTag":"block"\}' 'freedom.sh route must block CN domains'
Check-Contains 'freedom.sh' '\{"type":"field","ip":\["geoip:cn"\],"outboundTag":"block"\}' 'freedom.sh route must block CN IP'
Check-NotContains 'freedom.sh' '\{"type":"field","ip":\["geoip:private","geoip:cn"\],"outboundTag":"block"\}' 'freedom.sh route must keep private and CN IP blocks ordered separately'

Check-NotContains 'freedom.sh' 'sing-box|singbox|--kernel|FREEDOM_KERNEL|write_singbox_config|install_singbox_official|gen_reality_keys_singbox|choose_kernel' 'freedom.sh still contains sing-box/core-selection support'
Check-NotContains 'freedom.sh' '> "\$CONFIG_PATH"' 'freedom.sh must write config atomically instead of truncating config path directly'
Check-NotContains 'freedom.sh' 'chmod 644 "\$CONFIG_PATH"' 'freedom.sh must not make Xray config world-readable'
Check-NotContains 'freedom.sh' '/tmp/freedom-' 'freedom.sh must not use predictable /tmp log paths'
Check-NotContains 'freedom.sh' 'curl .*[|] sh' 'freedom.sh must not pipe installer downloads to sh'
Check-NotContains 'freedom.sh' 'bash -c "\$\(curl' 'freedom.sh must not execute downloaded installer inline'
Check-NotContains 'freedom.sh' 'xargs -r rm -f' 'freedom.sh backup cleanup must not use ls/xargs deletion'

$bashCandidates = @(Get-Command bash -ErrorAction SilentlyContinue | Where-Object { $_.Source -notlike '*\System32\bash.exe' -and $_.Source -notlike '*\WindowsApps\bash.exe' })
if ($bashCandidates.Count -gt 0) {
  & $bashCandidates[0].Source verify.sh
  if ($LASTEXITCODE -ne 0) {
    exit $LASTEXITCODE
  }
} else {
  Write-Host '[WARN] usable bash not found; skipped bash syntax checks.'
}

Write-Host '[OK] verification passed'
